INSERT INTO term_translations (term_id, locale, pronunciation_local, meaning_word, meaning_dev, abbreviation_of, examples) VALUES
('3f2b133a-1de5-4f55-8243-12e38b35d37d', 'ko', '컴프리헨션', '이해, 포괄', '리스트·딕셔너리·집합 등을 한 줄로 간결하게 생성하는 Python 고유 문법. for문과 조건을 대괄호 안에 넣어 표현한다.', NULL, '[{"code": "squares = [x**2 for x in range(10)]", "translation": "0부터 9까지의 제곱값 리스트를 한 줄로 생성"}, {"code": "even = {x for x in range(20) if x % 2 == 0}", "translation": "집합 컴프리헨션으로 짝수만 모은 set을 만든다"}]'),
('2a3543ee-89df-480a-b6ab-5f75db9e7bd0', 'ko', '딕셔너리', '사전', 'key-value 쌍으로 데이터를 저장하는 자료구조. 중괄호 {}로 생성하며 키로 빠르게 값을 조회할 수 있다.', NULL, '[{"code": "user = {\"name\": \"Kim\", \"age\": 28}\nprint(user[\"name\"])", "translation": "딕셔너리에서 키로 값을 조회한다"}, {"code": "user.get(\"email\", \"없음\")", "translation": "get()으로 키가 없을 때 기본값을 반환한다"}]'),
('9b9f46ed-6470-41f6-8b3e-8fd4fb6cd9c5', 'ko', '리스트', '목록', '순서가 있고 변경 가능한(mutable) 자료구조. 대괄호 []로 생성하며 다양한 타입의 요소를 담을 수 있다.', NULL, '[{"code": "fruits = [\"apple\", \"banana\"]\nfruits.append(\"cherry\")", "translation": "리스트에 append()로 요소를 추가한다"}, {"code": "nums = [1, 2, 3]\nnums.sort(reverse=True)", "translation": "리스트를 내림차순으로 정렬한다"}]'),
('2834b10c-0258-41c6-8e41-84cddf21bf41', 'ko', '핍', '패키지 설치 도구', 'Python 패키지를 설치·관리하는 공식 도구. PyPI(Python Package Index)에서 패키지를 다운로드한다.', 'Pip Installs Packages', '[{"code": "pip install requests", "translation": "requests 라이브러리를 설치한다"}, {"code": "pip freeze > requirements.txt", "translation": "설치된 패키지 목록을 requirements.txt에 저장한다"}]'),
('cdc74074-6c34-46fc-804e-480d20ea7a42', 'ko', '버추얼엔브', '가상 환경', '프로젝트별로 독립된 Python 환경을 만드는 도구. 프로젝트마다 다른 버전의 패키지를 설치할 수 있게 해준다.', NULL, '[{"code": "python -m venv myenv\nsource myenv/bin/activate", "translation": "가상환경을 만들고 활성화한다"}, {"code": "deactivate", "translation": "가상환경을 비활성화하고 시스템 Python으로 돌아간다"}]'),
('73b22289-013e-45e8-8b2b-6cd5961e5bbb', 'ko', '셀프', '자기 자신', '클래스의 인스턴스 메서드에서 인스턴스 자체를 가리키는 매개변수. 다른 언어의 this에 해당하며, Python에서는 명시적으로 첫 번째 인자로 적어야 한다.', NULL, '[{"code": "class Dog:\n    def bark(self):\n        print(f\"{self.name} 멍멍!\")", "translation": "self로 인스턴스의 name 속성에 접근한다"}, {"code": "def set_age(self, age):\n    self.age = age", "translation": "self를 통해 인스턴스 변수를 설정한다"}]'),
('b62b02ad-0bc3-4a34-aa81-f03a37a2cd5d', 'ko', '클래스', '부류, 유형', '객체를 만들기 위한 설계도(blueprint). 데이터(속성)와 동작(메서드)을 하나로 묶는 객체지향 프로그래밍의 핵심 구조.', NULL, '[{"code": "class Calculator:\n    def add(self, a, b):\n        return a + b", "translation": "Calculator 클래스에 add 메서드를 정의한다"}, {"code": "calc = Calculator()\nresult = calc.add(3, 5)", "translation": "클래스로 인스턴스를 만들고 메서드를 호출한다"}]'),
('99abebca-2cdf-407d-b6d0-8201ca586fcf', 'ko', '인헤릿', '상속하다', '기존 클래스의 속성과 메서드를 새 클래스가 물려받는 것. 코드 재사용과 계층 구조를 만드는 데 사용한다.', NULL, '[{"code": "class Animal:\n    def speak(self): pass\n\nclass Dog(Animal):\n    def speak(self):\n        return \"멍멍\"", "translation": "Dog 클래스가 Animal을 상속받아 speak을 재정의한다"}, {"code": "class Admin(User):\n    role = \"admin\"", "translation": "User를 상속받아 Admin 클래스를 만든다"}]'),
('51eae10e-3512-4c02-a6f4-9cabdc39ab7d', 'ko', '익셉션', '예외', '프로그램 실행 중 발생하는 오류. try/except로 잡아서 처리할 수 있다. ValueError, TypeError 등 다양한 종류가 있다.', NULL, '[{"code": "try:\n    result = 10 / 0\nexcept ZeroDivisionError:\n    print(\"0으로 나눌 수 없습니다\")", "translation": "0으로 나누기 예외를 잡아서 처리한다"}, {"code": "except FileNotFoundError as e:\n    print(f\"파일 없음: {e}\")", "translation": "파일을 찾을 수 없는 예외를 처리한다"}]'),
('1e738e8e-56e2-46df-b403-33a51cf98a4d', 'ko', '레이즈', '일으키다, 올리다', '예외를 의도적으로 발생시키는 키워드. 잘못된 입력이나 상태를 감지했을 때 명시적으로 에러를 던진다.', NULL, '[{"code": "if age < 0:\n    raise ValueError(\"나이는 음수일 수 없습니다\")", "translation": "나이가 음수이면 ValueError를 발생시킨다"}, {"code": "raise NotImplementedError(\"이 메서드를 구현하세요\")", "translation": "아직 구현되지 않은 메서드임을 알린다"}]'),
('c130881f-1e9f-4c61-8629-c952fc832f83', 'ko', '트라이', '시도하다', '예외가 발생할 수 있는 코드를 감싸는 키워드. except로 예외를 잡고, finally로 항상 실행할 코드를 지정한다.', NULL, '[{"code": "try:\n    data = json.loads(raw)\nexcept json.JSONDecodeError:\n    data = {}", "translation": "JSON 파싱 실패 시 빈 딕셔너리로 대체한다"}, {"code": "try:\n    f = open(\"data.txt\")\nfinally:\n    f.close()", "translation": "finally로 파일을 반드시 닫는다"}]'),
('acc2922a-845f-4829-aa71-6e466be836d6', 'ko', '모듈', '모듈, 단위', 'Python 코드가 담긴 .py 파일 하나를 모듈이라 한다. import로 불러와 재사용할 수 있다.', NULL, '[{"code": "import math\nprint(math.sqrt(16))", "translation": "math 모듈을 임포트하여 제곱근을 구한다"}, {"code": "from datetime import datetime\nnow = datetime.now()", "translation": "datetime 모듈에서 datetime 클래스만 가져온다"}]'),
('6cbb58ee-dbf7-4706-8fc2-01dd52d9d46c', 'ko', '패키지', '꾸러미', '여러 모듈을 디렉토리 구조로 묶은 것. __init__.py 파일이 있는 디렉토리가 패키지가 된다.', NULL, '[{"code": "mypackage/\n    __init__.py\n    utils.py\n    models.py", "translation": "__init__.py가 있는 디렉토리가 패키지가 된다"}, {"code": "from mypackage.utils import helper", "translation": "패키지 안의 모듈에서 함수를 가져온다"}]'),
('7695cbf1-db3b-4f4c-8416-78f2fdbe7c1f', 'ko', '독스트링', '문서화 문자열', '함수·클래스·모듈의 첫 줄에 작성하는 설명 문자열. 삼중 따옴표로 감싸며 help() 함수로 조회할 수 있다.', NULL, '[{"code": "def add(a, b):\n    \"\"\"두 수를 더한 결과를 반환한다.\"\"\"\n    return a + b", "translation": "삼중 따옴표로 함수 설명을 작성한다"}, {"code": "help(add)", "translation": "help()로 docstring을 확인할 수 있다"}]'),
('6c24c99e-ab16-4abb-a8d3-a53e5508e4fa', 'ko', '에프스트링', '포맷 문자열', 'Python 3.6+에서 도입된 문자열 포매팅 방법. 문자열 앞에 f를 붙이고 중괄호 {} 안에 변수나 표현식을 직접 넣는다.', NULL, '[{"code": "name = \"Kim\"\nprint(f\"안녕하세요, {name}님!\")", "translation": "f-string으로 변수를 문자열에 삽입한다"}, {"code": "print(f\"결과: {3 + 5}\")", "translation": "f-string 안에서 표현식 계산 결과를 출력"}]'),
('b0cf398a-f5e0-49c4-a7a4-3f95686bc779', 'ko', '언패킹', '풀기, 해체', '시퀀스의 요소를 여러 변수에 한 번에 할당하는 것. *를 사용하면 나머지 요소를 모을 수 있다.', NULL, '[{"code": "a, b, c = [1, 2, 3]", "translation": "리스트의 요소를 각각 a, b, c에 할당한다"}, {"code": "first, *rest = [1, 2, 3, 4, 5]", "translation": "*rest로 나머지 요소를 리스트로 모은다"}]'),
('b7a20d1c-5d39-4719-b5da-42049a81803e', 'ko', '아그스', '인자들', '함수에 가변 개수의 위치 인자를 전달할 때 사용하는 문법. *args로 튜플 형태로 받는다.', NULL, '[{"code": "def total(*args):\n    return sum(args)\ntotal(1, 2, 3)", "translation": "*args로 여러 숫자를 받아 합계를 구한다"}, {"code": "def log(msg, *args):\n    print(msg, *args)", "translation": "첫 인자 이후 나머지를 *args로 받는다"}]'),
('566b55c1-2089-4097-be51-4de2e6727b8f', 'ko', '크와그스', '키워드 인자들', '함수에 가변 개수의 키워드 인자를 전달할 때 사용하는 문법. **kwargs로 딕셔너리 형태로 받는다.', NULL, '[{"code": "def config(**kwargs):\n    for k, v in kwargs.items():\n        print(f\"{k} = {v}\")", "translation": "**kwargs로 키워드 인자를 딕셔너리로 받는다"}, {"code": "config(host=\"localhost\", port=8080)", "translation": "키워드 인자로 설정값을 전달한다"}]'),
('c7021ff8-04cd-4e78-8be8-61838b92cc2f', 'ko', '길', '글로벌 인터프리터 락', 'Python 인터프리터가 한 번에 하나의 스레드만 실행하도록 제한하는 잠금 장치. CPU 바운드 작업에서 멀티스레딩 성능을 제한하는 원인이 된다.', 'Global Interpreter Lock', '[{"code": "# GIL 때문에 CPU 작업은 멀티프로세싱 사용\nfrom multiprocessing import Pool", "translation": "GIL 우회를 위해 멀티프로세싱을 사용한다"}, {"code": "# I/O 작업은 GIL 영향이 적어 스레딩 가능\nimport threading", "translation": "I/O 바운드 작업은 스레딩으로도 효과적이다"}]'),
('9e134652-35dc-467c-8be6-cce9bd8cfe69', 'ko', '스레드', '실, 맥락', '프로세스 내에서 동시에 실행되는 작업 단위. Python에서는 GIL로 인해 I/O 바운드 작업에 주로 사용한다.', NULL, '[{"code": "import threading\nt = threading.Thread(target=worker)\nt.start()", "translation": "별도 스레드에서 worker 함수를 실행한다"}, {"code": "t.join()", "translation": "스레드가 끝날 때까지 기다린다"}]'),
('626183cf-e299-4742-bdd3-b6941aa0f152', 'ko', '타입 힌트', '타입 힌트', '변수나 함수의 인자·반환값에 기대되는 타입을 명시하는 문법. 실행에는 영향 없지만 가독성과 IDE 지원을 높인다.', NULL, '[{"code": "def greet(name: str) -> str:\n    return f\"Hello, {name}\"", "translation": "인자와 반환값의 타입을 명시한다"}, {"code": "age: int = 25\nscores: list[int] = [90, 85, 92]", "translation": "변수에 타입 힌트를 붙인다"}]'),
('e3a86d13-b745-4ddb-8ce5-3f45b4f9f261', 'ko', '데이터클래스', '데이터 클래스', 'Python 3.7+에서 도입된 데커레이터. __init__, __repr__, __eq__ 등을 자동 생성하여 데이터 저장용 클래스를 간결하게 만든다.', NULL, '[{"code": "from dataclasses import dataclass\n\n@dataclass\nclass Point:\n    x: float\n    y: float", "translation": "@dataclass로 __init__과 __repr__이 자동 생성된다"}, {"code": "@dataclass(frozen=True)\nclass Config:\n    host: str\n    port: int = 8080", "translation": "frozen=True로 불변 데이터클래스를 만든다"}]'),
('848c1e3c-8ba2-4250-b51e-c9385f6c2f0b', 'ko', '이뉴머레이트', '열거하다', '순회하면서 인덱스와 값을 동시에 반환하는 내장 함수. for문에서 인덱스가 필요할 때 사용한다.', NULL, '[{"code": "for i, fruit in enumerate([\"사과\", \"바나나\"]):\n    print(i, fruit)", "translation": "인덱스와 값을 동시에 가져온다"}, {"code": "for i, line in enumerate(lines, start=1):\n    print(f\"{i}: {line}\")", "translation": "start=1로 1번부터 번호를 매긴다"}]'),
('9ab04d4f-7269-40cf-9d6a-d06f2ecc3af5', 'ko', '짚', '지퍼, 묶다', '여러 이터러블을 병렬로 묶어 튜플 쌍을 만드는 내장 함수. 같은 위치의 요소끼리 짝지어 준다.', NULL, '[{"code": "names = [\"Kim\", \"Lee\"]\nscores = [90, 85]\nfor name, score in zip(names, scores):\n    print(name, score)", "translation": "두 리스트를 병렬로 순회한다"}, {"code": "dict(zip(keys, values))", "translation": "zip으로 키-값 쌍을 만들어 딕셔너리를 생성한다"}]'),
('575d49d8-fc17-4833-ba2c-0a1edbf06de3', 'ko', '맵', '지도, 대응시키다', '모든 요소에 함수를 적용해 새로운 이터러블을 반환하는 내장 함수.', NULL, '[{"code": "nums = [1, 2, 3]\nresult = list(map(str, nums))", "translation": "모든 숫자를 문자열로 변환한다"}, {"code": "map(lambda x: x.upper(), words)", "translation": "lambda와 함께 모든 단어를 대문자로 변환"}]'),
('8a63fbfa-19cc-4bce-a7f1-8b9b8d30130a', 'ko', '위드', '~와 함께', '컨텍스트 매니저를 사용하는 키워드. 파일이나 DB 연결 등 자원을 안전하게 열고 자동으로 닫아준다.', NULL, '[{"code": "with open(\"data.txt\") as f:\n    content = f.read()", "translation": "with문으로 파일을 열면 블록 종료 시 자동으로 닫힌다"}, {"code": "with db.connection() as conn:\n    conn.execute(query)", "translation": "DB 연결을 with문으로 안전하게 관리한다"}]'),
('c555584a-042c-42b5-a57f-b8dd222c6404', 'ko', '글로벌', '전역의', '함수 안에서 전역 변수를 수정할 때 사용하는 키워드. 남용하면 코드 추적이 어려워진다.', NULL, '[{"code": "count = 0\ndef increment():\n    global count\n    count += 1", "translation": "global 선언으로 함수 안에서 전역 변수를 수정한다"}, {"code": "# global 없이 전역 변수에 할당하면 UnboundLocalError 발생", "translation": "global 키워드 없이 수정하면 에러가 발생한다"}]'),
('71ef577b-eb32-4c90-8bca-3a6ce4522ccf', 'ko', '넌', '아무것도 아닌', 'Python에서 값이 없음을 나타내는 싱글턴 객체. 다른 언어의 null/nil에 해당한다. is None으로 비교한다.', NULL, '[{"code": "result = None\nif result is None:\n    print(\"결과 없음\")", "translation": "is None으로 값이 없는지 확인한다"}, {"code": "def find(items, key):\n    return items.get(key)  # 없으면 None 반환", "translation": "값이 없을 때 None이 기본 반환값이 된다"}]'),
('a3d315ad-e205-4dca-b0ac-7a028cf067fa', 'ko', '패스', '지나가다, 통과', '아무것도 하지 않는 빈 문장. 구조만 잡아놓고 구현을 나중에 할 때 자리 표시자(placeholder)로 사용한다.', NULL, '[{"code": "def todo():\n    pass  # 나중에 구현", "translation": "pass로 빈 함수의 구문 에러를 방지한다"}, {"code": "class EmptyError(Exception):\n    pass", "translation": "커스텀 예외 클래스를 빈 상태로 정의한다"}]'),
('8ad6143c-8ca4-4e74-ba82-544b1835c9ea', 'ko', '이즈인스턴스', '~의 인스턴스인지', '객체가 특정 클래스의 인스턴스인지 확인하는 내장 함수. type()보다 상속 관계까지 고려하므로 더 권장된다.', NULL, '[{"code": "isinstance(42, int)  # True", "translation": "42가 int의 인스턴스인지 확인한다"}, {"code": "isinstance(dog, Animal)  # True (상속 포함)", "translation": "상속받은 클래스도 True를 반환한다"}]'),
('4818317a-2d7f-4e8a-adbd-840a86eef806', 'ko', '프로퍼티', '속성', '@property 데커레이터로 메서드를 속성처럼 접근할 수 있게 만드는 기능. getter/setter를 우아하게 구현한다.', NULL, '[{"code": "class Circle:\n    def __init__(self, r):\n        self._r = r\n    @property\n    def area(self):\n        return 3.14 * self._r ** 2", "translation": "circle.area로 메서드를 속성처럼 호출한다"}, {"code": "@area.setter\ndef area(self, value):\n    self._r = (value / 3.14) ** 0.5", "translation": "setter로 값 할당 시 자동 변환 로직을 추가한다"}]')
